//
// On PowerPC a _Float16 aggregate is deliberately NOT a homogeneous floating-point
// aggregate (HFA). Contrast take_f2 below: a struct of float is a real HFA and is
// passed in FPRs (IR: [2 x float]). A struct/array of _Float16 is instead passed
// like an integer aggregate -- coerced to iN / [N x i64] in GPRs on ELFv2, and as
// a byval pointer (memory) on AIX. HFA classification for _Float16 is left to the
// OpenPOWER ELFv2 psABI.
//
// RUN: %clang_cc1 -triple powerpc64le-unknown-linux-gnu -target-cpu pwr9 -mfloat16 \
// RUN:   -O2 -emit-llvm %s -o - | FileCheck %s --check-prefixes=ELFV2
// RUN: %clang_cc1 -triple powerpc64-ibm-aix -target-cpu pwr9 -mfloat16 \
// RUN:   -O2 -emit-llvm %s -o - | FileCheck %s --check-prefixes=AIX

struct F2 { float a, b; };                            // real HFA of float (contrast)
struct H2 { _Float16 a, b; };
struct H4 { _Float16 a, b, c, d; };
struct H8 { _Float16 a, b, c, d, e, f, g, h; };

// Contrast: a float HFA is passed as [2 x float] (FPRs f1, f2).
// ELFV2-LABEL: define dso_local float @take_f2(
// ELFV2-SAME: [2 x float] [[S_COERCE:%.*]]) local_unnamed_addr #[[ATTR0:[0-9]+]] {
// ELFV2-NEXT:  [[ENTRY:.*:]]
// ELFV2-NEXT:    [[S_COERCE_FCA_0_EXTRACT:%.*]] = extractvalue [2 x float] [[S_COERCE]], 0
// ELFV2-NEXT:    ret float [[S_COERCE_FCA_0_EXTRACT]]
//
// AIX-LABEL: define float @take_f2(
// AIX-SAME: ptr nofree noundef readonly byval([[STRUCT_F2:%.*]]) align 8 captures(none) [[S:%.*]]) local_unnamed_addr #[[ATTR0:[0-9]+]] {
// AIX-NEXT:  [[ENTRY:.*:]]
// AIX-NEXT:    [[TMP0:%.*]] = load float, ptr [[S]], align 8, !tbaa [[FLOAT_TBAA5:![0-9]+]]
// AIX-NEXT:    ret float [[TMP0]]
//
float take_f2(struct F2 s) { return s.a; }

